+fn encode_scope_entries<'a>(entries: impl IntoIterator<Item = &'a str>) -> String {
+    let mut encoded = String::new();
+    for entry in entries {
+        encoded.push_str(&entry.len().to_string());
+        encoded.push(':');
+        encoded.push_str(entry);
+        encoded.push('|');
+    }
+    encoded
